const synthetics = require('@aws/synthetics-puppeteer');
const log = require('@aws/synthetics-logger');
const syntheticsConfiguration = synthetics.getConfiguration();
const theseus_xml_checker = require('theseus-xml-checker'); // updated to check for recent data
//const AWS = require("aws-sdk")
const {CloudWatchClient, PutMetricDataCommand} = require("@aws-sdk/client-cloudwatch");
const config = {};
var cloudwatch = new CloudWatchClient(config);

async function publishMetric(rxStatus) {

    var params = {
        MetricData: [ 
          {
            MetricName: 'Theseus-Rx-Status',
            Dimensions: [{Name: 'rxid', Value: rxStatus.rxid}],
            Values: [(rxStatus.present ? 1: 0)]
          }
        ],
        Namespace: 'Theseus' 
      };
      const command = new PutMetricDataCommand(params);
      const resp = await cloudwatch.send(command)
                console.log("putMetricData successful: returned %s", resp);           // successful response
};

const theseusXmlCanary = async function () {

    syntheticsConfiguration.setConfig({
        restrictedHeaders: [], // Value of these headers will be redacted from logs and reports
        restrictedUrlParameters: [] // Values of these url parameters will be redacted from logs and reports
    });

    // Handle validation for positive scenario
    const validateSuccessful = async function(res) {
        expectedRxList = process.env.EXPECTED_RX_LIST;
        return new Promise((resolve, reject) => {
            if (res.statusCode < 200 || res.statusCode > 299) {
                throw new Error(res.statusCode + ' ' + res.statusMessage);
            }

            let responseBody = '';
            res.on('data', (d) => {
                responseBody += d;
            });

            res.on('end', async () => {
                var rxStatus;
                
                try {
                    rxStatus = await theseus_xml_checker.checkXML(responseBody, expectedRxList);
                } catch(err)  {
                    console.log("caught ", err, " about to reject");
                    throw err;
                    return;
                }

                try {
                    await Promise.all(rxStatus.map(async (status) => {await publishMetric(status)}))
                } catch(err) {
                    console.log("Caught ", err, "about to reject");
                    throw err;
                    return;
                }

                if (!rxStatus.every(status => status.present))
                {
                    throw new Error("Missing receivers!");
                    return;
                }
    
                resolve(true);

            })

        })
    }
                   

    // Set request option for Verify eu-west-2.console.aws.amazon.com
    let requestOptionsStep1 = {
        hostname: 'home.theseus.bbctest01.uk',
        method: 'GET',
        path: '/rsci/receivers.xml',
        port: '443',
        protocol: 'https:',
        body: "",
        auth: 'drm:es201980',
        headers: {'User-Agent': ''}
    };
    requestOptionsStep1['headers']['User-Agent'] = [synthetics.getCanaryUserAgentString(), requestOptionsStep1['headers']['User-Agent']].join(' ');

    // Set step config option for Verify theseus.bbctest01.uk
   let stepConfig1 = {
        includeRequestHeaders: true,
        includeResponseHeaders: true,
        includeRequestBody: true,
        includeResponseBody: true,
        continueOnHttpStepFailure: true
    };

    await synthetics.executeHttpStep('Verify_home_theseus_bbctest01_uk_rsci_receivers_xml', requestOptionsStep1, validateSuccessful, stepConfig1);

    return true;

};

exports.handler = async () => {
    try {
        return await theseusXmlCanary();
    } catch (error) 
    {
        console.log("Error: ", error)
        return false;
    }

};

